import { useState } from "react";

export default function BannerAnnouncement01() {
  const [visible, setVisible] = useState(true);
  if (!visible) return null;
  return (
    <div className="relative flex items-center justify-center gap-3 bg-gradient-to-r from-violet-700 to-fuchsia-600 px-6 py-2.5 text-sm text-white">
      <span className="rounded-full bg-white/20 px-2 py-0.5 text-xs font-bold">NEU</span>
      <p className="font-medium">
        {{projectName}} v3.0 ist live — jetzt mit KI-Copilot.{" "}
        <a href="#" className="font-bold underline underline-offset-2 hover:no-underline">
          Mehr erfahren →
        </a>
      </p>
      <button
        onClick={() => setVisible(false)}
        className="absolute right-4 text-white/60 transition hover:text-white"
        aria-label="Schließen"
      >
        ✕
      </button>
    </div>
  );
}

